colsdata.lang:
// BO columns
paging: true,
scrollX: true,
//scrollY: 300,
//scrollCollapse: true,
pageLength: 20,
lengthMenu: [[10, 20, 100, 250, 500, 1000], [10, 20, 100, 250, 500, 1000]],
layout: {
    topStart: {
        search: {
            placeholder: 'Type search here',
        },
    },
    topEnd: 'info',
    bottomStart: 'paging',
    bottomEnd: 'pageLength',
},
order: [[2, "asc" ]], // order column descending
"columnDefs": [
    {
        "orderable": false,
        "targets": [3, 4, 5],
    },
    {
        width: 100,
        targets: [3, 4, 5, 6],
    },
    {
        width: 300,
        targets: [0],
    },
],
//asStripeClasses: [] // disable zebra coloring of rows
//bSortClasses: false // disable coloring of sorted column
columns: [
	{
        data: null,
        render: function (data, type, row) {
            if (row.domain != null) {
                return row.domain;
            }
            else if (row.server != null) {
                return row.server;
            }
            else {
                return '';
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.aliases != null) {
                return row.aliases;
            }
            else {
                return '-';
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            return '<a href="' + row.path + '/manage?lang='+getZMILang()+'" target="_blank">' + row.breadcrumbs + '</a>';
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.attr_dc_type != null) {
                return row.attr_dc_type;
            }
            else {
                return '-'
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.protocol != null) {
                return row.protocol;
            }
            else {
                return '-';
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.workflow) {
                return true;
            }
            else {
                return false;

            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.comments != null) {
                return row.comments;
            }
            else {
                return '-';
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.etracker != null) {
                return row.etracker;
            }
            else {
                return '-';
            }
        }
	},
],
