// https://datatables.net/examples/api/multi_filter_select.html
initComplete: function () {
    i = 0;
    this.api().columns().every(function() {
        var column = this;
        var column_filter_for = [3, 4, 5];
        if (i==3) {
            key = 'attr_dc_type';
        }
        if (i==4) {
            key = 'protocol';
        }
        if (i==5) {
            key = 'workflow';
        }
        if (column_filter_for.includes(i)) {
            var select = $('<select><option value=""></option></select>')
                .appendTo( $(column.header()) )
                .on('change', function () {
                    var val = $.fn.dataTable.util.escapeRegex(
                        $(this).val()
                    );
                    column
                        .search( val ? '^'+val+'$' : '', true, false )
                        .draw();
                } );
            var myArray = new Array();
            column.data().each( function ( d, j ) {
                if (d[key] !== undefined) {
                    myArray.push(d[key]);
                }
            } );
            let unique = [...new Set(myArray)];
            unique.sort().forEach( function ( d, j ) {
                select.append('<option value="'+d+'">'+d+'</option>')
            } );
        }
        else {
            column.text = '';
        }
        i++;
    } );
},
/* https://github.com/gyrocode/jquery-datatables-alphabetSearch
alphabetSearch: {
    column: 1
}, */

// EO columns

// BO processCustomJS
function processCustomJS(table) {

    $('#e1723245 tbody').on('click', 'td', function () {
        var tr = this.closest('tr');
        var row = table.row(tr);
        if (this.cellIndex == 0 || this.cellIndex == 1 || this.cellIndex == 2 || this.cellIndex == 3 || this.cellIndex == 4 || this.cellIndex == 5) {
            title = row.data()['title'];
            descr = row.data()['attr_dc_description'];
            if (descr == null) {
                descr = 'n/a';
            }
            subject = row.data()['attr_dc_subject'];
            if (subject == null) {
                subject = 'n/a';
            }
            languages = row.data()['languages'];
            protocol = row.data()['protocol'];
            if (protocol == null) {
                protocol = 'n/a';
            }
            workflow = row.data()['workflow'];
            if (workflow == true) {
                workflow = '<a href="'+row.data()['path']+'/workflow_manager/manage_main?lang='+getZMILang()+'" target="_blank">Workflow</a>';
                workflow_nodes = row.data()['workflow_nodes'];
            }
            else {
                workflow = 'Workflow';
                workflow_nodes = 'n/a';
            }
            comments = row.data()['comments'];
            if (comments == null) {
                comments = 'n/a';
            }
            etracker = row.data()['etracker'];
            if (etracker == null) {
                etracker = 'n/a';
            }
            domain = row.data()['domain'];
            server = row.data()['server'];
            aliases = row.data()['aliases'];
            if (domain == null) {
                domain = 'n/a';
            }
            if (server == null) {
                domain = 'n/a';
            }
            else {
                domain = server;
            }
            if (aliases == null) {
                aliases = 'n/a';
            }
            titleimg = row.data()['titleimage'];
            if (titleimg != null) {
                titleimg = '<p><img src="https://edit.cms.unibe.ch'+row.data()['path']+'/'+titleimg['data']['@filename']+'" width="50%" /></p>';
            }
            else {
                titleimg = '';
            }
            $('#datatableModalTitle').text(title);
            $('#datatableModalBody').html(
                titleimg+
                '<p><strong>Description:</strong> '+descr+'</p>'+
                '<p><strong>Keywoords:</strong> '+subject+'</p>'+
                '<p><strong>Comments:</strong> '+comments+'</p>'+
                '<p><strong>Languages:</strong> <code>'+languages+'</code></p>'+
                '<p><strong>ETracker:</strong> <code>'+etracker+'</code></p>'+
                '<p><strong>'+workflow+':</strong> <code>'+workflow_nodes+'</code></p>'+
                '<p><strong>Protocol:</strong> <code>'+protocol+'</code></p>'+
                '<p><strong>Domain:</strong> <code>'+domain+'</code></p>'+
                '<p><strong>Aliases:</strong> <code>'+aliases+'</code></p>'+
                '<p><a href="'+row.data()['path']+'/manage_users?lang='+getZMILang()+'" target="_blank" class="btn btn-light" style="border:1px solid #aaa;">Users</a> '+
                '<a href="'+row.data()['path']+'/manage_customize?lang='+getZMILang()+'#Custom" target="_blank" class="btn btn-light" style="border:1px solid #aaa;">Settings</a> '+
                '<a href="'+row.data()['path']+'/manage_executeMetacmd?id=manage_activatePub&lang='+getZMILang()+'" target="_blank" class="btn btn-primary">Activate</a> '+
                '<a href="'+row.data()['path']+'/manage_executeMetacmd?id=manage_deactivatePub&lang='+getZMILang()+'" target="_blank" class="btn btn-danger">Deactivate</a></p>'
            );
            $('#datatableModal').modal('toggle');
        }
    });
    $('#e1723245 tbody').on('mouseover', 'td', function () {
        var tr = this.closest('tr');
        var row = table.row(tr);
        if (this.cellIndex == 0 || this.cellIndex == 1 || this.cellIndex == 2 || this.cellIndex == 3 || this.cellIndex == 4 || this.cellIndex == 5) {
            $(this).css('cursor', 'pointer');
        }
    });

}
// EO processCustomJS
